package com.datamaster.module.assets.controller.admin.assetchild.geo;import javax.annotation.Resource;import javax.servlet.http.HttpServletResponse;import javax.validation.Valid;import java.util.Arrays;import cn.hutool.core.date.DateUtil;import java.util.List;import io.swagger.v3.oas.annotations.Operation;import io.swagger.v3.oas.annotations.tags.Tag;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.validation.annotation.Validated;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;import com.datamaster.common.core.domain.AjaxResult;import com.datamaster.common.core.page.PageParam;import com.datamaster.common.annotation.Log;import com.datamaster.common.core.controller.BaseController;import com.datamaster.common.core.domain.CommonResult;import com.datamaster.common.core.page.PageResult;import com.datamaster.common.enums.BusinessType;import com.datamaster.common.utils.object.BeanUtils;import com.datamaster.common.utils.poi.ExcelUtil;import com.datamaster.common.exception.enums.GlobalErrorCodeConstants;import com.datamaster.module.assets.controller.admin.assetchild.geo.vo.AssetsAssetGeoPageReqVO;import com.datamaster.module.assets.controller.admin.assetchild.geo.vo.AssetsAssetGeoRespVO;import com.datamaster.module.assets.controller.admin.assetchild.geo.vo.AssetsAssetGeoSaveReqVO;import com.datamaster.module.assets.convert.assetchild.geo.AssetsAssetGeoConvert;import com.datamaster.module.assets.dal.dataobject.assetchild.geo.AssetsAssetGeoDO;import com.datamaster.module.assets.service.assetchild.geo.IAssetsAssetGeoService;/** * 数据资产-矢量Controller * * @author DATAMASTER * @date 2025-04-14 */@Tag(name = "数据资产-矢量")@RestController@RequestMapping("/ast/assetGeo")@Validated
public class AssetsAssetGeoController extends BaseController {    @Resource    private IAssetsAssetGeoService AssetsAssetGeoService;    @Operation(summary = "查询数据资产-矢量列表")    @PreAuthorize("@ss.hasPermi('da:assetGeo:list')")    @GetMapping("/list")    public CommonResult<PageResult<AssetsAssetGeoRespVO>> list(AssetsAssetGeoPageReqVO AssetsAssetGeo) {        PageResult<AssetsAssetGeoDO> page = AssetsAssetGeoService.getAssetGeoPage(AssetsAssetGeo);        return CommonResult.success(BeanUtils.toBean(page, AssetsAssetGeoRespVO.class));    }    @Operation(summary = "导出数据资产-矢量列表")    @PreAuthorize("@ss.hasPermi('da:assetGeo:export')")    @Log(title = "数据资产-矢量", businessType = BusinessType.EXPORT)    @PostMapping("/export")    public void export(HttpServletResponse response, AssetsAssetGeoPageReqVO exportReqVO) {        exportReqVO.setPageSize(PageParam.PAGE_SIZE_NONE);        List<AssetsAssetGeoDO> list = (List<AssetsAssetGeoDO>) AssetsAssetGeoService.getAssetGeoPage(exportReqVO).getRows();        ExcelUtil<AssetsAssetGeoRespVO> util = new ExcelUtil<>(AssetsAssetGeoRespVO.class);        util.exportExcel(response, AssetsAssetGeoConvert.INSTANCE.convertToRespVOList(list), "应用管理数据");    }    @Operation(summary = "导入数据资产-矢量列表")    @PreAuthorize("@ss.hasPermi('da:assetGeo:import')")    @Log(title = "数据资产-矢量", businessType = BusinessType.IMPORT)    @PostMapping("/importData")    public AjaxResult importData(MultipartFile file, boolean updateSupport) throws Exception {        ExcelUtil<AssetsAssetGeoRespVO> util = new ExcelUtil<>(AssetsAssetGeoRespVO.class);        List<AssetsAssetGeoRespVO> importExcelList = util.importExcel(file.getInputStream());        String operName = getUsername();        String message = AssetsAssetGeoService.importAssetGeo(importExcelList, updateSupport, operName);        return success(message);    }    @Operation(summary = "获取数据资产-矢量详细信息")    @PreAuthorize("@ss.hasPermi('da:assetGeo:query')")    @GetMapping(value = "/{id}")    public CommonResult<AssetsAssetGeoRespVO> getInfo(@PathVariable("id") Long id) {        AssetsAssetGeoDO AssetsAssetGeoDO = AssetsAssetGeoService.getAssetGeoById(id);        return CommonResult.success(BeanUtils.toBean(AssetsAssetGeoDO, AssetsAssetGeoRespVO.class));    }    @Operation(summary = "新增数据资产-矢量")    @PreAuthorize("@ss.hasPermi('da:assetGeo:add')")    @Log(title = "数据资产-矢量", businessType = BusinessType.INSERT)    @PostMapping    public CommonResult<Long> add(@Valid @RequestBody AssetsAssetGeoSaveReqVO AssetsAssetGeo) {        AssetsAssetGeo.setCreatorId(getUserId());        AssetsAssetGeo.setCreateBy(getNickName());        AssetsAssetGeo.setCreateTime(DateUtil.date());        return CommonResult.toAjax(AssetsAssetGeoService.createAssetGeo(AssetsAssetGeo));    }    @Operation(summary = "修改数据资产-矢量")    @PreAuthorize("@ss.hasPermi('da:assetGeo:edit')")    @Log(title = "数据资产-矢量", businessType = BusinessType.UPDATE)    @PutMapping    public CommonResult<Integer> edit(@Valid @RequestBody AssetsAssetGeoSaveReqVO AssetsAssetGeo) {        AssetsAssetGeo.setUpdatorId(getUserId());        AssetsAssetGeo.setUpdateBy(getNickName());        AssetsAssetGeo.setUpdateTime(DateUtil.date());        return CommonResult.toAjax(AssetsAssetGeoService.updateAssetGeo(AssetsAssetGeo));    }    @Operation(summary = "删除数据资产-矢量")    @PreAuthorize("@ss.hasPermi('da:assetGeo:remove')")    @Log(title = "数据资产-矢量", businessType = BusinessType.DELETE)    @DeleteMapping("/{ids}")    public CommonResult<Integer> remove(@PathVariable Long[] ids) {        return CommonResult.toAjax(AssetsAssetGeoService.removeAssetGeo(Arrays.asList(ids)));    }}